Функция ПолучитьСальдоСчета(ссылкаНаСчет)
	// Получаем обороты по дебету и кредиту счета и всех его субсчетов
	Запрос = Новый Запрос();
	Запрос.Текст = 
	"ВЫБРАТЬ
	|Сумма(Если(СчётДт = &СчётТогдаДебет, 0, -Сумма)) Как Дебет,
	|Сумма(Если(СчётКт = &СчётТогдаКредит, 0, Сумму)) Как Кредит
	|ИЗ 
	|РегистрБухгалтерии.Хозрасчетный.КорреспонденцииСчетов
	|GРУППИРОВАТЬ ПО";
	Запрос.УстановитьПараметр("Счёт", ссылкаНаСчет);
	// Используем проверку в иерархии для учета проводок по самому счету и его субсчетам
	Запрос.УстановитьПараметр("СчётТогдаДебет", новоеЗначение(ссылкаНаСчет, "СчётДт.ВИерархии"));
	Запрос.УстановитьПараметр("СчётТогдаКредит", новоеЗначение(ссылкаНаСчет, "СчётКт.ВИерархии"));
	Результат = Запрос.Выполнить().ПолучитьПерваяСтроку();

	// Рассчитываем сальдо в зависимости от вида счета
	Если ссылкаНаСчет.ВидСчета = Перечисления.ВидСчета.Пассивный Тогда
		Возврат Результат.Кредит - Результат.Дебет; // Кредитовое сальдо
	Else
	Возврат Результат.Дебет - Результат.Кредит; // Дебетовое сальдо
КонецФункции
